// Worked focus: cmem-allocator-injection — Inject matched allocate, resize, and release operations with context and failure semantics.
/* Evidence: cmem-worked-cmem-functions-callbacks-interfaces-5 */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 6064; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


typedef int (*transform_callback)(int value, void *context);

static int add_context(int value, void *context) {
  int *offset = (int *)context;
  return offset == NULL ? value : value + *offset;
}

static int worked_cmem_functions_callbacks_interfaces_5(transform_callback callback, void *context, int context_live, int value) {
  if (callback == NULL || !context_live) return -1;
  return callback(value, context);
}

int main(void) {
  int offset = 6;
  int stale = worked_cmem_functions_callbacks_interfaces_5(add_context, &offset, 0, 10);
  int live = worked_cmem_functions_callbacks_interfaces_5(add_context, &offset, 1, 10);
  int invariant = stale == -1 && live == 16;
  printf("callback live=%d invariant=%d\n", live, invariant);
  return invariant ? 0 : 1;
}

